 13→var emailsFormat string
 14→
 15→var emailsCmd = &cobra.Command{
 16→	Use:   "emails",
 17→	Short: "Manage synced emails",
 18→}
 19→
 20→var emailsListCmd = &cobra.Command{
 21→	Use:   "list",
 22→	Short: "List synced emails",
 23→	RunE: func(cmd *cobra.Command, args []string) error {
 24→		d, err := db.Open()
 25→		if err != nil {
 26→			return err
 27→		}
 28→		defer d.Close()
 29→
 30→		class, _ := cmd.Flags().GetString("class")
 31→		limit, _ := cmd.Flags().GetInt("limit")
 32→
 33→		list, err := email.List(d, email.ListOptions{Class: class, Limit: limit})
 34→		if err != nil {
 35→			return err
 36→		}
 37→
 38→		if emailsFormat == "json" {
 39→			enc := json.NewEncoder(os.Stdout)
 40→			enc.SetIndent("", "  ")
 41→			return enc.Encode(list)
 42→		}
 43→
 44→		for _, e := range list {
 45→			date := e.Date
 46→			if len(date) >= 10 {
 47→				date = date[:10]
 48→			}
 49→			fmt.Printf("  [%s] %s → %s\n    %s\n", e.Class, date, e.Subject, e.Snippet)
 50→		}
 51→		return nil
 52→	},
 53→}
 54→
 55→var emailsStatsCmd = &cobra.Command{
 56→	Use:   "stats",
 57→	Short: "Show email statistics",
 58→	RunE: func(cmd *cobra.Command, args []string) error {
 59→		d, err := db.Open()
 60→		if err != nil {
 61→			return err
 62→		}
 63→		defer d.Close()
 64→
 65→		stats, err := email.Stats(d)
 66→		if err != nil {
 67→			return err
 68→		}
 69→
 70→		if emailsFormat == "json" {
 71→			enc := json.NewEncoder(os.Stdout)
 72→			enc.SetIndent("", "  ")
 73→			return enc.Encode(stats)
 74→		}
 75→
 76→		fmt.Printf("  Total emails: %d\n", stats.Total)
 77→		fmt.Printf("  Unclassified: %d\n", stats.Unclassified)
 78→		fmt.Printf("  Date range: %s to %s\n", stats.DateRange.Earliest, stats.DateRange.Latest)
 79→		fmt.Println("  By class:")
 80→		for class, count := range stats.ByClass {
 81→			fmt.Printf("    %s: %d\n", class, count)
 82→		}
 83→		return nil
 84→	},
 85→}
 86→
 87→var emailsClassifyCmd = &cobra.Command{
 88→	Use:   "classify",
 89→	Short: "Update email classifications from stdin",
 90→	Long:  "Reads JSON array from stdin: [{\"id\": \"msg-123\", \"class\": \"outbound\", \"confidence\": 0.95}]",
 91→	RunE: func(cmd *cobra.Command, args []string) error {
 92→		d, err := db.Open()
 93→		if err != nil {
 94→			return err
 95→		}
 96→		defer d.Close()
 97→
 98→		var updates []email.ClassifyUpdate
 99→		if err := json.NewDecoder(os.Stdin).Decode(&updates); err != nil {
100→			return fmt.Errorf("parsing stdin: %w", err)
101→		}
102→
103→		count, err := email.Classify(d, updates)
104→		if err != nil {
105→			return err
106→		}
107→
108→		fmt.Printf("  ✓ Classified %d emails\n", count)
109→		return nil
110→	},
111→}
112→
113→var emailsCheckCmd = &cobra.Command{
114→	Use:   "check",
115→	Short: "Check email sending health",
116→	RunE: func(cmd *cobra.Command, args []string) error {
117→		d, err := db.Open()
118→		if err != nil {
119→			return err
120→		}
121→		defer d.Close()
122→
123→		health, err := email.Check(d)
124→		if err != nil {
125→			return err
126→		}
127→
128→		if emailsFormat == "json" {
129→			enc := json.NewEncoder(os.Stdout)
130→			enc.SetIndent("", "  ")
131→			return enc.Encode(health)
132→		}
133→
134→		fmt.Printf("  Emails/day (last 7d): %.1f\n", health.DailyAvg7d)
135→		fmt.Printf("  Emails/day (last 30d): %.1f\n", health.DailyAvg30d)
136→		fmt.Printf("  Unique recipients (last 30d): %d\n", health.UniqueRecipients30d)
137→		return nil
138→	},
139→}
140→
141→func init() {
142→	emailsCmd.PersistentFlags().StringVar(&emailsFormat, "format", "", "Output format (json)")
143→	emailsListCmd.Flags().String("class", "", "Filter by classification")
144→	emailsListCmd.Flags().Int("limit", 0, "Max results")
145→	emailsCmd.AddCommand(emailsListCmd)
146→	emailsCmd.AddCommand(emailsStatsCmd)
147→	emailsCmd.AddCommand(emailsClassifyCmd)
148→	emailsCmd.AddCommand(emailsCheckCmd)
149→	rootCmd.AddCommand(emailsCmd)
150→}
