155→	Use:   "stale",
156→	Short: "List skills that likely need regeneration",
157→	RunE: func(cmd *cobra.Command, args []string) error {
158→		d, err := db.Open()
159→		if err != nil {
160→			return err
161→		}
162→		defer d.Close()
163→
164→		items, err := session.ListStaleSkills(d, skillsLimit)
165→		if err != nil {
166→			return err
167→		}
168→
169→		if skillsFormat == "json" {
170→			return session.PrintJSON(items)
171→		}
172→
173→		if len(items) == 0 {
174→			fmt.Println("No skills need regeneration right now.")
175→			return nil
176→		}
177→
178→		for _, item := range items {
179→			versionLabel := "untracked"
180→			if item.ActiveVersion > 0 {
181→				versionLabel = fmt.Sprintf("v%d", item.ActiveVersion)
182→			}
183→			fmt.Printf("%-25s %s\n", item.SkillName, versionLabel)
