198→
199→	skillsCmd.AddCommand(skillsListCmd)
200→	skillsCmd.AddCommand(skillsHistoryCmd)
201→	skillsCmd.AddCommand(skillsRollbackCmd)
202→	skillsCmd.AddCommand(skillsSaveCmd)
203→	skillsCmd.AddCommand(skillsStaleCmd)
