 16→var (
 17→	sendTo          string
 18→	sendCc          string
 19→	sendSubject     string
 20→	sendBody        string
 21→	sendSequence    string
 22→	sendCampaign    string
 23→	sendTaskID      string
 24→	sendSendType    string
 25→	sendContactName string
 26→)
 27→
 28→var sendCmd = &cobra.Command{
 29→	Use:   "send",
 30→	Short: "Send an email via Gmail",
 31→	Long:  "Send an email through your connected Gmail account.",
 32→	RunE: func(cmd *cobra.Command, args []string) error {
 33→		if sendSequence != "" && sendTaskID != "" {
 34→			return fmt.Errorf("--sequence and --task-id cannot be used together")
 35→		}
 36→
 37→		// Get sender address from config
 38→		cfg, err := project.Load()
 39→		if err != nil {
 40→			return fmt.Errorf("loading config: %w", err)
 41→		}
 42→
 43→		gmail, ok := cfg.Connectors["gmail"]
 44→		if !ok || !gmail.Connected {
 45→			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
 46→		}
 47→
 48→		d, err := db.Open()
 49→		if err != nil {
 50→			return fmt.Errorf("opening database: %w", err)
 51→		}
 52→		defer d.Close()
 53→
 54→		mailbox, err := sequence.EnsureMailbox(d, gmail.Account, "gmail")
 55→		if err != nil {
 56→			return fmt.Errorf("ensuring mailbox state: %w", err)
 57→		}
 58→
 59→		now := timeNow()
 60→		effectiveSendType := sequence.NormalizeSendType(sendSendType)
 61→		var task *sequence.Task
 62→		selectedMailbox := mailbox
 63→		if sendCampaign != "" && sendTaskID == "" {
 64→			if campaign, err := sequence.CampaignByName(d, sendCampaign); err == nil {
 65→				if sendSequence == "" {
 66→					sendSequence = campaign.SequenceName
 67→				}
 68→				if campaignMailbox, err := sequence.CampaignMailbox(d, campaign); err == nil && campaignMailbox != nil {
 69→					selectedMailbox = campaignMailbox
 70→				}
 71→			}
 72→		}
 73→		if sendSequence != "" {
 74→			effectiveSendType = sequence.SendTypeFirstTouch
 75→		}
 76→		if sendTaskID != "" {
 77→			task, err = sequence.TaskByID(d, sendTaskID)
 78→			if err != nil {
 79→				return err
 80→			}
 81→			effectiveSendType = task.SendType
 82→			selectedMailbox, err = sequence.ResolveTaskMailbox(d, *task, gmail.Account, now)
 83→			if err != nil {
 84→				return err
 85→			}
 86→			if sendTo == "" {
 87→				sendTo = task.ContactEmail
 88→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 89→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 90→			}
 91→			if sendSubject == "" || sendBody == "" {
 92→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 93→				if err != nil {
 94→					return err
 95→				}
 96→				if sendSubject == "" {
 97→					sendSubject = renderedSubject
 98→				}
 99→				if sendBody == "" {
100→					sendBody = renderedBody
101→				}
102→			}
103→		}
104→
105→		if sendTo == "" {
106→			return fmt.Errorf("recipient (--to) is required")
107→		}
108→		if sendSubject == "" {
109→			return fmt.Errorf("subject (--subject) is required")
110→		}
111→		if sendBody == "" {
112→			return fmt.Errorf("body (--body) is required")
113→		}
114→		if sendSequence != "" {
115→			enrollment, err := sequence.ActiveEnrollmentForContact(d, selectedMailbox.ID, sendTo)
116→			if err != nil {
117→				return err
118→			}
119→			if enrollment != nil {
120→				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
121→			}
122→		}
123→		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
124→			return err
125→		} else if suppressed {
126→			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
127→		}
128→
129→		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, now); err != nil {
130→			return err
131→		}
132→
133→		srv, err := email.NewClient("")
134→		if err != nil {
135→			return fmt.Errorf("connecting to Gmail: %w", err)
136→		}
137→		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
138→		if fromAddress == "" {
139→			fromAddress = strings.TrimSpace(selectedMailbox.Email)
140→		}
141→
142→		var threadID string
143→		if task != nil {
144→			threadID = task.ThreadID
145→		}
146→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
147→			To:       sendTo,
148→			Cc:       sendCc,
149→			Subject:  sendSubject,
150→			Body:     sendBody,
151→			ThreadID: threadID,
152→		})
153→		if err != nil {
154→			if task != nil {
155→				_ = sequence.MarkTaskAttempt(d, task.ID, now, err)
156→				_ = sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusFailed, "", "", err.Error())
157→				_ = sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
158→					MailboxID:    selectedMailbox.ID,
159→					EnrollmentID: task.EnrollmentID,
160→					TaskID:       task.ID,
161→					ContactEmail: sendTo,
162→					SendType:     effectiveSendType,
163→					Status:       sequence.TaskSendStatusFailed,
164→					Subject:      sendSubject,
165→					Error:        err.Error(),
166→					AttemptedAt:  now,
167→				})
168→			}
169→			return err
170→		}
171→
172→		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, now); err != nil {
173→			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
174→		}
175→		if err := email.StoreEmail(d, &email.RawMessage{
176→			ID:        sent.MessageID,
177→			Source:    "gmail",
178→			Direction: "outbound",
179→			ThreadID:  sent.ThreadID,
180→			Subject:   sendSubject,
181→			FromEmail: fromAddress,
182→			ToEmails:  recipientsJSON(sendTo),
183→			CcEmails:  recipientsJSON(sendCc),
184→			Date:      now.UTC().Format(time.RFC3339),
185→			Labels:    `["SENT"]`,
186→		}); err != nil {
187→			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
188→		}
189→		if task != nil {
190→			if err := sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
191→				return fmt.Errorf("email sent (message ID: %s) but failed to update send state for task %s: %w", sent.MessageID, task.ID, err)
192→			}
193→		}
194→		var enrollmentID, taskID string
195→		if task != nil {
196→			enrollmentID = task.EnrollmentID
197→			taskID = task.ID
198→		}
199→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
200→			MailboxID:    selectedMailbox.ID,
201→			EnrollmentID: enrollmentID,
202→			TaskID:       taskID,
203→			ContactEmail: sendTo,
204→			SendType:     effectiveSendType,
205→			Status:       sequence.TaskSendStatusSent,
206→			Subject:      sendSubject,
207→			MessageID:    sent.MessageID,
208→			AttemptedAt:  now,
209→		}); err != nil {
210→			return fmt.Errorf("email sent (message ID: %s) but failed to log send attempt: %w", sent.MessageID, err)
211→		}
212→
213→		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
214→
215→		if sendSequence != "" {
216→			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
217→				SequenceName: sendSequence,
218→				CampaignName: sendCampaign,
219→				MailboxID:    selectedMailbox.ID,
220→				ContactEmail: sendTo,
221→				ContactName:  sendContactName,
222→				Subject:      sendSubject,
223→				InitialBody:  sendBody,
224→				ThreadID:     sent.ThreadID,
225→				MessageID:    sent.MessageID,
226→				SentAt:       now,
227→			})
228→			if err != nil {
229→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
230→			}
231→
232→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
233→			if nextTask != nil {
234→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
235→			}
236→		}
237→
238→		if task != nil {
239→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
240→				TaskID:    task.ID,
241→				ThreadID:  sent.ThreadID,
242→				MessageID: sent.MessageID,
243→				MailboxID: selectedMailbox.ID,
244→				SentAt:    now,
245→			})
246→			if err != nil {
