126→			s.settings = cfg.Settings
127→		}
128→	}
129→
130→	// Load DB stats (graceful — may not exist)
131→	if !db.Exists() {
132→		return s
133→	}
134→	d, err := db.Open()
135→	if err != nil {
136→		return s
137→	}
