261→	if d == nil {
262→		return nil
263→	}
264→	defer d.Close()
265→
266→	session.AddEvent(d, input.SessionID, "prompt", input)
267→	session.Logger().Info("prompt", "session_id", input.SessionID)
268→	session.FlushLog()
269→	return nil
270→}
