769→// --- Auto-update ---
770→
771→const (
772→	updateCacheFile   = ".nurge/update_check.json"
773→	updateCheckTTL    = 24 * time.Hour
774→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
775→)
776→
777→type updateCache struct {
778→	LatestVersion string `json:"latest_version"`
779→	CheckedAt     string `json:"checked_at"`
780→	UpdatedAt     string `json:"updated_at,omitempty"`
781→}
782→
783→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
784→// Returns a message for the banner, or empty string.
785→func checkAndAutoUpdate() string {
786→	// Read cache
787→	cache := readUpdateCache()
788→
789→	// If checked recently, just report
790→	if cache != nil && cache.CheckedAt != "" {
791→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
792→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
793→			// Cache is fresh — check if we just updated
794→			if cache.UpdatedAt != "" {
795→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
796→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
797→					// Clear the updated flag for next time
798→					cache.UpdatedAt = ""
799→					writeUpdateCache(cache)
800→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
801→				}
802→			}
803→			return ""
804→		}
805→	}
806→
807→	// Check for latest version (with timeout)
808→	latest := fetchLatestVersion()
809→	if latest == "" {
810→		// Network failed — update cache timestamp so we don't retry immediately
811→		if cache == nil {
812→			cache = &updateCache{}
813→		}
814→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
815→		writeUpdateCache(cache)
816→		return ""
817→	}
818→
819→	// Save to cache
820→	if cache == nil {
821→		cache = &updateCache{}
822→	}
823→	cache.LatestVersion = latest
824→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
825→
826→	// Compare: if current version matches latest, no update needed
827→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
828→		writeUpdateCache(cache)
829→		return ""
830→	}
831→
832→	// Different version — auto-update
833→	if runAutoUpdate() {
834→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
835→		writeUpdateCache(cache)
836→		return fmt.Sprintf("Updating to %s...", latest)
837→	}
838→
839→	writeUpdateCache(cache)
840→	return ""
841→}
842→
843→func readUpdateCache() *updateCache {
844→	data, err := os.ReadFile(updateCacheFile)
845→	if err != nil {
846→		return nil
847→	}
848→	var c updateCache
849→	if err := json.Unmarshal(data, &c); err != nil {
850→		return nil
851→	}
852→	return &c
853→}
854→
855→func writeUpdateCache(c *updateCache) {
856→	data, err := json.Marshal(c)
857→	if err != nil {
858→		return
859→	}
860→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
861→	os.WriteFile(updateCacheFile, data, 0644)
862→}
863→
864→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
865→func fetchLatestVersion() string {
866→	client := &http.Client{Timeout: 3 * time.Second}
867→	resp, err := client.Get(githubReleasesURL)
868→	if err != nil {
869→		return ""
870→	}
871→	defer resp.Body.Close()
872→
873→	if resp.StatusCode != 200 {
874→		return ""
875→	}
876→
877→	var release struct {
878→		TagName string `json:"tag_name"`
879→	}
880→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
881→		return ""
882→	}
883→	return release.TagName
884→}
885→
886→// runAutoUpdate runs the install script in the background. Returns true if launched.
887→func runAutoUpdate() bool {
888→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
889→	if err := cmd.Start(); err != nil {
890→		return false
891→	}
892→	// Don't wait — let it run in background
893→	go cmd.Wait()
894→	return true
895→}
896→
897→func capitalize(s string) string {
898→	if s == "" {
899→		return s
900→	}
901→	return strings.ToUpper(s[:1]) + s[1:]
902→}
903→
904→func formatCount(n int) string {
905→	if n >= 1000 {
906→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
907→	}
908→	return fmt.Sprintf("%d", n)
909→}
